      "n": 5,
      "column": "left",
      "text": "Uṣrangajt manni/ tad juhs\niṣtrutḥinafectees/ un likſeet Koh-\nku us Mutti.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Kad es arri pats to peemin-\nnu/ tad es behdajohs/un Trihze-\nfchana mannu Mecfu apxemin.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Kapehz dshwo tee Besdee-\nwigee/ tohp wezzi/ un winnu\nPadohms tohp warrens?\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Winnu Sehla pastahw\nwinnu Preekchá ar winneem/\nun winnu Behrni irr preeſsch\nwinnu Azzim.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Winnu Namman irr\nMeers bes Bibjaschanas/ un\nDeewa Rihſte pahr teem ne\nnahk.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Winnu Wehrfis aplezz/\nun ue paleek bes Augteem/ win-\nna Gohws weddahs/ un ne is-\nmettahs.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Sawus Behrnians tee\nissuht ka Awju Pulku/ un win-\nnu jauni Behrni lehka.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Tee irr lihgfini ar Bun-\ngahm un Kohklehm/ un preeza-\njahs ar Stabulehm.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Tee pawadda twas Dee-\nnas eekſch Labklahſchanas/ un\nweenâ Azzumirkii tee Kappá ee-\ngrinst.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Tatschu tee fakka us te\nSTIPRU DEEWU: Atkah-\npees no mums/ jo mehs tawus\nZettus ne gribbam atſiht.\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Kahds irrtas Wiſnuwar-\nrenajs/ ka mums tam btj kal-\npoht? un kahds Labbnus mums\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "(Bet)rangi/ winnu Lab-\nbuns ne stahw winnu Kohká/\ntadeht to Besdeewign Pa-\ndohms tahfu no mannim buhs\nbuht.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Ka nodsiffihs to Besdee-\nwigu Saifchuns/ un winnu\nSamaitatchana pahr teem\nnahks? winſch iṣdallihs (teem)\nSird-Ehſtus eekſch Jawas Duf-\nmibas.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Tee ta patt buhs ka Rug-\ngaji preekſch Wehja/ un ka Pel-\nlus/ ko Weefuls peepechi iṣput-\ntina.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Deewg paturr winna\nNelaimibu us winna Behrneem/\nwiṣch arri tan paſchain atmak-\nsahs/ ka wiṣch to mattihs.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Winnu Azzis redſehs\nwinna Bohja-Geſchanu/ un\nwiṣch dsers no ta Wiſnuwarre-\nna Bahrsibas.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Jo kahds tam labs\nPrahts buhtu pee Jawu Namman\nkad wiṣch jaw nohſt irr/ kad\nwinnu Mehneschu Pulks irr pa-\nihſinahts.\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Kaß griβbetn tam\nSTIPRAM DEEWAM\nSafrachann matzyht/ kad\nwiṣch tohs Augstajus teefa?\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Schis nomirst ar pilln\nSpehkn/ wiṣfaschki ar Meern/\nun labbi flahdamees.\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Winnu Peenu-Spanni\nirr pilln ar Beena/ nn winna\nRauli irr no Smadsenehm tanki.\n"
    }
  ],
